// ==========================================================================
// GENETICS
// ==========================================================================

// ---------------------------------------------------------------------------
// GENETICS — the molecular biology the mutation lab needs, kept in code so the
// science is always correct. Standard genetic code, transcription, translation,
// and a mutation-effect classifier (silent / missense / nonsense / frameshift).
// ---------------------------------------------------------------------------

// DNA template base -> mRNA base (transcription). A pairs with U in RNA.
const TRANSCRIBE = { A: 'U', T: 'A', C: 'G', G: 'C' };

// Standard genetic code: mRNA codon (5'->3') -> amino acid single letter.
// '*' marks a STOP codon.
const CODON_TABLE = {
  UUU: 'F', UUC: 'F', UUA: 'L', UUG: 'L',
  CUU: 'L', CUC: 'L', CUA: 'L', CUG: 'L',
  AUU: 'I', AUC: 'I', AUA: 'I', AUG: 'M',
  GUU: 'V', GUC: 'V', GUA: 'V', GUG: 'V',
  UCU: 'S', UCC: 'S', UCA: 'S', UCG: 'S',
  CCU: 'P', CCC: 'P', CCA: 'P', CCG: 'P',
  ACU: 'T', ACC: 'T', ACA: 'T', ACG: 'T',
  GCU: 'A', GCC: 'A', GCA: 'A', GCG: 'A',
  UAU: 'Y', UAC: 'Y', UAA: '*', UAG: '*',
  CAU: 'H', CAC: 'H', CAA: 'Q', CAG: 'Q',
  AAU: 'N', AAC: 'N', AAA: 'K', AAG: 'K',
  GAU: 'D', GAC: 'D', GAA: 'E', GAG: 'E',
  UGU: 'C', UGC: 'C', UGA: '*', UGG: 'W',
  CGU: 'R', CGC: 'R', CGA: 'R', CGG: 'R',
  AGU: 'S', AGC: 'S', AGA: 'R', AGG: 'R',
  GGU: 'G', GGC: 'G', GGA: 'G', GGG: 'G',
};

// Single letter -> 3-letter name, for readable readouts.
const AA_NAMES = {
  F: 'Phe', L: 'Leu', I: 'Ile', M: 'Met', V: 'Val', S: 'Ser', P: 'Pro',
  T: 'Thr', A: 'Ala', Y: 'Tyr', H: 'His', Q: 'Gln', N: 'Asn', K: 'Lys',
  D: 'Asp', E: 'Glu', C: 'Cys', W: 'Trp', R: 'Arg', G: 'Gly', '*': 'STOP',
};

const DNA_BASES = ['A', 'T', 'C', 'G'];

// A short demonstration gene for the mutation lab, chosen so that a SINGLE
// substitution can produce every effect type (silent / missense / nonsense),
// and any insert/delete shows a frameshift. Transcribes to AUG-UAC-AAG
// (Met-Tyr-Lys); mutating the Tyr codon reaches a STOP in one step.
const GENE_TEMPLATE = ['T', 'A', 'C', 'A', 'T', 'G', 'T', 'T', 'C'];

// Transcribe a DNA template (array of bases) into an mRNA string.
function transcribe(template) {
  return template.map((b) => TRANSCRIBE[b] ?? '?').join('');
}

// Translate mRNA into codons + amino acids, reading in-frame from the start.
// Trailing bases that don't complete a codon are ignored; translation ends at
// the first STOP codon (as the ribosome does).
function translate(mrna) {
  const out = [];
  for (let i = 0; i + 3 <= mrna.length; i += 3) {
    const codon = mrna.slice(i, i + 3);
    const aa = CODON_TABLE[codon] ?? '?';
    out.push({ codon, aa, name: AA_NAMES[aa] ?? '???' });
    if (aa === '*') break;
  }
  return out;
}

// Apply a mutation to a DNA template, returning a NEW template array.
//  { kind: 'substitution', pos, base } — replace the base at pos
//  { kind: 'insertion', pos, base }    — insert a base before pos
//  { kind: 'deletion', pos }           — remove the base at pos
function applyMutation(template, mut) {
  const next = [...template];
  if (mut.kind === 'substitution') next[mut.pos] = mut.base;
  else if (mut.kind === 'insertion') next.splice(mut.pos, 0, mut.base);
  else if (mut.kind === 'deletion') next.splice(mut.pos, 1);
  return next;
}

const aaSeq = (protein) => protein.map((p) => p.aa).join('');

// Classify a mutation's effect by comparing the original and mutated proteins.
// Returns { type, label, detail }.
function classifyEffect(template, mut) {
  const original = translate(transcribe(template));
  const mutated = translate(transcribe(applyMutation(template, mut)));

  if (mut.kind === 'insertion' || mut.kind === 'deletion') {
    return {
      type: 'frameshift',
      label: 'FRAMESHIFT',
      detail:
        `A single ${mut.kind === 'insertion' ? 'inserted' : 'deleted'} base shifts the ` +
        'reading frame, so every codon downstream is misread — usually scrambling the whole protein.',
    };
  }

  const before = aaSeq(original);
  const after = aaSeq(mutated);

  if (before === after) {
    return {
      type: 'silent',
      label: 'SILENT',
      detail: 'The codon still spells the same amino acid, so the protein is unchanged. The genetic code is redundant.',
    };
  }
  if (after.includes('*') && !before.slice(0, after.indexOf('*')).includes('*') && after.length < before.length) {
    return {
      type: 'nonsense',
      label: 'NONSENSE',
      detail: 'The change created a premature STOP codon, so the protein is cut short and usually non-functional.',
    };
  }
  return {
    type: 'missense',
    label: 'MISSENSE',
    detail: 'One codon now codes for a different amino acid — the protein is built but altered at that position.',
  };
}

// Describe the effect of a whole edited gene vs its original (handles the
// mutation lab's cumulative edits, including length-changing indels).
function describeEffect(original, current) {
  if (original.length === current.length && original.every((b, i) => b === current[i])) {
    return { type: 'none', label: 'WILD TYPE', detail: 'No mutation yet — this is the original gene. Change, insert, or delete a base to see what happens.' };
  }
  if (current.length !== original.length) {
    return {
      type: 'frameshift',
      label: 'FRAMESHIFT',
      detail: 'Inserting or deleting a base shifts the reading frame, so every codon downstream is misread — usually wrecking the whole protein.',
    };
  }
  const before = aaSeq(translate(transcribe(original)));
  const after = aaSeq(translate(transcribe(current)));
  if (before === after) {
    return { type: 'silent', label: 'SILENT', detail: 'The codon still spells the same amino acid — the protein is unchanged. The genetic code is redundant.' };
  }
  if (after.includes('*') && !before.includes('*')) {
    return { type: 'nonsense', label: 'NONSENSE', detail: 'The change created a premature STOP codon, so the protein is cut short and usually non-functional.' };
  }
  return { type: 'missense', label: 'MISSENSE', detail: 'A codon now codes for a different amino acid — the protein is built, but altered at that position.' };
}


// ==========================================================================
// AUDIO
// ==========================================================================

// Tiny procedural audio: footsteps synthesized with WebAudio so we ship zero
// sound assets. The context is created lazily on the first step, which happens
// after the pointer-lock click, so the browser autoplay policy is satisfied.
let ctx = null;
let noiseBuffer = null;

function getContext() {
  if (!ctx) {
    const AC = window.AudioContext || window.webkitAudioContext;
    if (!AC) return null;
    ctx = new AC();
  }
  if (ctx.state === 'suspended') ctx.resume();
  return ctx;
}

function getNoiseBuffer(c) {
  if (!noiseBuffer) {
    const len = Math.floor(c.sampleRate * 0.1);
    noiseBuffer = c.createBuffer(1, len, c.sampleRate);
    const data = noiseBuffer.getChannelData(0);
    for (let i = 0; i < len; i += 1) data[i] = Math.random() * 2 - 1;
  }
  return noiseBuffer;
}

// A short filtered noise burst — reads as a soft footstep on a hard lab floor.
function playFootstep({ sprint = false } = {}) {
  const c = getContext();
  if (!c || c.state !== 'running') return;

  const t = c.currentTime;
  const src = c.createBufferSource();
  src.buffer = getNoiseBuffer(c);
  src.playbackRate.value = 0.85 + Math.random() * 0.3;

  const filter = c.createBiquadFilter();
  filter.type = 'lowpass';
  filter.frequency.value = sprint ? 900 : 650;
  filter.Q.value = 0.8;

  const gain = c.createGain();
  const peak = (sprint ? 0.09 : 0.06) * (0.85 + Math.random() * 0.3);
  gain.gain.setValueAtTime(peak, t);
  gain.gain.exponentialRampToValueAtTime(0.001, t + 0.09);

  src.connect(filter).connect(gain).connect(c.destination);
  src.start(t);
  src.stop(t + 0.1);
}

// ---------------------------------------------------------------------------
// SFX + ambient — sampled clips (Kenney CC0: Interface Sounds, Sci-Fi Sounds,
// Music Jingles), in /public/assets/audio. Footsteps stay procedural above;
// these are the discrete gameplay cues. The lesson event bus (useLesson.emit)
// is the single choke point that drives them, so the renderer stays untouched.
// ---------------------------------------------------------------------------

const SFX_BASE = '/assets/audio';

// One-shot cues and their volumes (0–1), kept modest so narration sits on top.
const SFX = {
  lesson_start: { file: 'lesson_start.ogg', volume: 0.5 },
  door_open: { file: 'door_open.ogg', volume: 0.45 },
  base_collect: { file: 'base_collect.ogg', volume: 0.6 }, // glassy clink — the vials are glass
  pair_correct: { file: 'pair_correct.ogg', volume: 0.55 },
  pair_wrong: { file: 'pair_wrong.ogg', volume: 0.4 },
  lesson_complete: { file: 'lesson_complete.ogg', volume: 0.6 },
  ui_click: { file: 'ui_click.ogg', volume: 0.35 },
};

// Which cue each lesson event fires. Events absent here are silent.
const EVENT_SOUND = {
  lesson_start: 'lesson_start',
  phase_enter: 'door_open', // walking into the next (now-unlocked) room
  base_identified: 'base_collect',
  pair_correct: 'pair_correct',
  pair_wrong: 'pair_wrong',
  lesson_complete: 'lesson_complete',
};

const canPlayFiles = typeof window !== 'undefined' && typeof Audio !== 'undefined';
const MUTE_KEY = 'sq_muted';
const AMBIENT_VOLUME = 0.18;

let muted = canPlayFiles && window.localStorage?.getItem(MUTE_KEY) === '1';
let ambient = null;
const clipCache = new Map();

function baseClip(name) {
  const spec = SFX[name];
  if (!spec) return null;
  if (!clipCache.has(name)) {
    const el = new Audio(`${SFX_BASE}/${spec.file}`);
    el.preload = 'auto';
    clipCache.set(name, el);
  }
  return clipCache.get(name);
}

// Play a one-shot cue. Cloning lets the same sound overlap itself (rapid correct
// answers) instead of restarting. Autoplay rejections before the first gesture
// are swallowed — the first real sound is lesson_start, fired from a click.
function playSound(name) {
  if (!canPlayFiles || muted) return;
  const spec = SFX[name];
  const base = baseClip(name);
  if (!base || !spec) return;
  const el = base.cloneNode();
  el.volume = spec.volume;
  el.play().catch(() => {});
}

// Route a lesson event to its cue, and manage the ambient bed's lifecycle.
function playEvent(event) {
  if (event === 'lesson_start') startAmbient();
  if (event === 'lesson_complete') stopAmbient();
  const sound = EVENT_SOUND[event];
  if (sound) playSound(sound);
}

// Low looping lab hum. Started on lesson_start (a user gesture) so autoplay is
// allowed; stopped when the lesson finishes.
function startAmbient() {
  if (!canPlayFiles || ambient) return;
  ambient = new Audio(`${SFX_BASE}/ambient_lab.ogg`);
  ambient.loop = true;
  ambient.volume = muted ? 0 : AMBIENT_VOLUME;
  ambient.play().catch(() => {});
}

function stopAmbient() {
  if (ambient) {
    ambient.pause();
    ambient = null;
  }
}

function isMuted() {
  return muted;
}

// Toggle all sampled audio; returns the new state so a UI control can reflect it.
function setMuted(next) {
  muted = next;
  if (canPlayFiles) window.localStorage?.setItem(MUTE_KEY, next ? '1' : '0');
  if (ambient) ambient.volume = next ? 0 : AMBIENT_VOLUME;
  return muted;
}


