// ==========================================================================
// useKeyboard
// ==========================================================================

// Tracks which movement keys are held. Returns a ref to a Set of key codes so
// the render loop can read it without causing re-renders.
function useKeyboard() {
  const keys = useRef(new Set());
  useEffect(() => {
    const down = (e) => keys.current.add(e.code);
    const up = (e) => keys.current.delete(e.code);
    const blur = () => keys.current.clear();
    window.addEventListener('keydown', down);
    window.addEventListener('keyup', up);
    window.addEventListener('blur', blur);
    return () => {
      window.removeEventListener('keydown', down);
      window.removeEventListener('keyup', up);
      window.removeEventListener('blur', blur);
    };
  }, []);
  return keys;
}


// ==========================================================================
// useLesson
// ==========================================================================

// Central lesson state machine. Owns the current phase and per-interaction
// progress. All mutations return NEW state (immutable) per project style rules.
// Telemetry hook points are stubbed so the pipeline/analytics side (CLAUDE.md
// §6.3) can subscribe later without touching the renderer.
function useLesson(lesson = DEFAULT_LESSON) {
  const [phaseIndex, setPhaseIndex] = useState(0);
  const [started, setStarted] = useState(false);
  const [finished, setFinished] = useState(false);
  // Bumped on begin/restart so the renderer can teleport the player back to the
  // spawn — the Player never remounts, so a state reset alone leaves the camera
  // stranded wherever the last run ended.
  const [runId, setRunId] = useState(0);

  // Interaction progress buckets, keyed by phaseId so phases stay independent.
  const [basesFound, setBasesFound] = useState([]); // p2 explore
  const [pairIndex, setPairIndex] = useState(0); // p3/p4 current rung
  const [pairErrors, setPairErrors] = useState(0); // wrong placements THIS phase

  // Lesson-cumulative accuracy telemetry (survives phase changes; drives the
  // finish report and the "mutation" feedback in the build station). Every wrong
  // base the student snaps onto the strand is a mutation the cell would have made.
  const [correctPlacements, setCorrectPlacements] = useState(0);
  const [mutations, setMutations] = useState(0);

  const phases = lesson.phases;
  const phase = phases[phaseIndex];
  const totalPairs = TEMPLATE_STRAND.length;

  const emit = useCallback(
    (event, payload = {}) => {
      // Sampled SFX + ambient are driven off this same event stream.
      playEvent(event);
      // Placeholder telemetry sink. Real build writes to Firestore
      // sessions/{code}/events (CLAUDE.md §6.2).
      if (typeof window !== 'undefined' && window.__SQ_DEBUG) {
        // eslint-disable-next-line no-console
        console.log('[telemetry]', phase?.phaseId, event, payload);
      }
    },
    [phase]
  );

  const phaseComplete = useMemo(() => {
    if (!phase) return false;
    const it = phase.interaction;
    switch (it.type) {
      case 'cinematic':
        return true; // advanced manually via Continue
      case 'explore':
        return basesFound.length >= 4;
      case 'pairing':
        return pairIndex >= totalPairs;
      default:
        return true;
    }
  }, [phase, basesFound, pairIndex, totalPairs]);

  const resetInteraction = useCallback(() => {
    setBasesFound([]);
    setPairIndex(0);
    setPairErrors(0);
  }, []);

  const goTo = useCallback(
    (index) => {
      const clamped = Math.max(0, Math.min(phases.length - 1, index));
      resetInteraction();
      setPhaseIndex(clamped);
      emit('phase_enter', { index: clamped });
    },
    [phases.length, resetInteraction, emit]
  );

  const next = useCallback(() => {
    if (phaseIndex >= phases.length - 1) {
      setFinished(true);
      emit('lesson_complete');
      return;
    }
    goTo(phaseIndex + 1);
  }, [phaseIndex, phases.length, goTo, emit]);

  const prev = useCallback(() => goTo(phaseIndex - 1), [phaseIndex, goTo]);

  const begin = useCallback(() => {
    setStarted(true);
    setRunId((r) => r + 1);
    emit('lesson_start');
  }, [emit]);

  const restart = useCallback(() => {
    resetInteraction();
    setCorrectPlacements(0);
    setMutations(0);
    setPhaseIndex(0);
    setFinished(false);
    setStarted(true);
    setRunId((r) => r + 1);
  }, [resetInteraction]);

  // --- interaction callbacks -------------------------------------------------
  const logBase = useCallback(
    (base) => {
      setBasesFound((found) => (found.includes(base) ? found : [...found, base]));
      emit('base_identified', { base });
    },
    [emit]
  );

  const submitPair = useCallback(
    (correct) => {
      if (correct) {
        setPairIndex((i) => i + 1);
        setCorrectPlacements((n) => n + 1);
        emit('pair_correct', { rung: pairIndex });
      } else {
        setPairErrors((e) => e + 1);
        setMutations((m) => m + 1);
        emit('pair_wrong', { rung: pairIndex });
      }
      return correct;
    },
    [pairIndex, emit]
  );

  // Strand-building accuracy over the whole lesson. 100% until the first
  // placement so an untouched run never reads as a failure.
  const attempts = correctPlacements + mutations;
  const fidelity = attempts === 0 ? 100 : Math.round((correctPlacements / attempts) * 100);

  return {
    lesson,
    phases,
    phase,
    phaseIndex,
    started,
    finished,
    runId,
    phaseComplete,
    progress: { basesFound, pairIndex, pairErrors, totalPairs, correctPlacements, mutations, fidelity },
    actions: { begin, next, prev, goTo, restart, logBase, submitPair },
  };
}


// ==========================================================================
// BlobShadow
// ==========================================================================

let blobTexture = null;
function getBlobTexture() {
  if (blobTexture) return blobTexture;
  const size = 128;
  const canvas = document.createElement('canvas');
  canvas.width = canvas.height = size;
  const ctx = canvas.getContext('2d');
  const g = ctx.createRadialGradient(size / 2, size / 2, size * 0.05, size / 2, size / 2, size / 2);
  g.addColorStop(0, 'rgba(10, 16, 28, 0.4)');
  g.addColorStop(0.55, 'rgba(10, 16, 28, 0.18)');
  g.addColorStop(1, 'rgba(10, 16, 28, 0)');
  ctx.fillStyle = g;
  ctx.fillRect(0, 0, size, size);
  blobTexture = new THREE.CanvasTexture(canvas);
  return blobTexture;
}

// Cheap fake contact shadow: a radial-gradient plane laid on the floor. Sells
// "this object stands on the ground" without any shadow-mapped lights.
// `y` sits just above the floor grid overlay to avoid z-fighting.
function BlobShadow({ radius = 1, y = 0.035, opacity = 1 }) {
  return (
    <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, y, 0]}>
      <planeGeometry args={[radius * 2, radius * 2]} />
      <meshBasicMaterial map={getBlobTexture()} transparent opacity={opacity} depthWrite={false} />
    </mesh>
  );
}


// ==========================================================================
// Nearby
// ==========================================================================

const EXIT_PAD = 3; // hysteresis so visibility can't flap at the boundary

// Mounts children only while the player is within `radius` of `center` ([x, z]).
// Culls whole rooms / lights / labels that the fog has already swallowed.
// Unmounting (rather than toggling `visible`) also removes drei <Html> labels,
// which live in the DOM and ignore Object3D visibility.
function Nearby({ center, radius, children }) {
  const [near, setNear] = useState(() => {
    const p = playerState.position;
    return Math.hypot(p.x - center[0], p.z - center[1]) < radius;
  });
  const nearRef = useRef(near);

  useFrame(() => {
    const p = playerState.position;
    const d = Math.hypot(p.x - center[0], p.z - center[1]);
    const next = nearRef.current ? d < radius + EXIT_PAD : d < radius;
    if (next !== nearRef.current) {
      nearRef.current = next;
      setNear(next);
    }
  });

  return near ? children : null;
}


// ==========================================================================
// EnvMap
// ==========================================================================

// Generates a neutral studio environment map locally (no network fetch) and
// assigns it as scene.environment, so every metallic / rough material has
// something real to reflect. Without this, metalness renders flat grey.
function EnvMap({ intensity = 0.5 }) {
  const gl = useThree((s) => s.gl);
  const scene = useThree((s) => s.scene);

  useEffect(() => {
    const pmrem = new THREE.PMREMGenerator(gl);
    const tex = pmrem.fromScene(new RoomEnvironment(), 0.04).texture;
    scene.environment = tex;
    scene.environmentIntensity = intensity;
    return () => {
      if (scene.environment === tex) scene.environment = null;
      tex.dispose();
      pmrem.dispose();
    };
  }, [gl, scene, intensity]);

  return null;
}


// ==========================================================================
// Nucleotide
// ==========================================================================

// A single base "bead" on the helix. Optionally clickable (explore mode) and
// optionally pulsing (the active rung the student is solving).
function Nucleotide({ base, position, radius = 0.28, pulse = false, clickable = false, onClick }) {
  const ref = useRef();
  const info = BASES[base] ?? { color: '#94a3b8' };

  useFrame((state) => {
    if (!ref.current) return;
    const s = pulse ? 1 + Math.sin(state.clock.elapsedTime * 4) * 0.14 : 1;
    ref.current.scale.setScalar(s);
  });

  return (
    <mesh
      ref={ref}
      position={position}
      onClick={
        clickable
          ? (e) => {
              e.stopPropagation();
              onClick?.(base);
            }
          : undefined
      }
      onPointerOver={clickable ? () => (document.body.style.cursor = 'pointer') : undefined}
      onPointerOut={clickable ? () => (document.body.style.cursor = 'auto') : undefined}
    >
      <sphereGeometry args={[radius, 12, 12]} />
      <meshStandardMaterial
        color={info.color}
        emissive={info.color}
        emissiveIntensity={pulse ? 1.1 : 0.5}
        roughness={0.25}
        metalness={0.15}
      />
    </mesh>
  );
}


// ==========================================================================
// RnaPolymerase
