// The enzyme that "unzips" the helix during transcription. Rendered inside the
// helix group so it rides along with rotation and clamps the active rung.
// Placeholder blob — swap for a sourced enzyme GLB from /public/assets/models.
function RnaPolymerase({ position }) {
  const ref = useRef();
  useFrame((state) => {
    if (!ref.current) return;
    const t = state.clock.elapsedTime;
    ref.current.rotation.y = t * 0.6;
    ref.current.scale.setScalar(1 + Math.sin(t * 3) * 0.05);
  });
  return (
    <group ref={ref} position={position}>
      <mesh>
        <icosahedronGeometry args={[0.62, 1]} />
        <meshStandardMaterial
          color="#f8fafc"
          emissive="#5eead4"
          emissiveIntensity={0.5}
          roughness={0.4}
          metalness={0.2}
          flatShading
          transparent
          opacity={0.85}
        />
      </mesh>
      <mesh position={[0, 0, 0]}>
        <icosahedronGeometry args={[0.78, 1]} />
        <meshBasicMaterial color="#5eead4" wireframe transparent opacity={0.25} />
      </mesh>
    </group>
  );
}


// ==========================================================================
// DnaHelix
// ==========================================================================

// The hero object. Renders a template strand always, and reveals the
// complementary / mRNA strand rung-by-rung as the student solves pairs.
//
// modes:
//   'display'  -> both strands fully shown (structure viewing)
//   'explore'  -> both strands shown, template beads are clickable
//   'pairing'  -> partner strand builds up to `builtCount`
//
// Beads and rung bonds are grouped by base and drawn with instancing: one draw
// call per base colour instead of one mesh per bead (~40 draws → ~10).

const INSTANCE_LIMIT = TEMPLATE_STRAND.length * 2; // both strands, worst case

function BeadInstances({ base, items, clickable, onBaseClick }) {
  const color = (BASES[base] ?? { color: '#94a3b8' }).color;
  return (
    <Instances limit={INSTANCE_LIMIT}>
      <sphereGeometry args={[0.28, 12, 12]} />
      <meshStandardMaterial color={color} emissive={color} emissiveIntensity={0.5} roughness={0.25} metalness={0.15} />
      {items.map((it) => (
        <Instance
          key={it.key}
          position={it.position}
          onClick={
            clickable
              ? (e) => {
                  e.stopPropagation();
                  onBaseClick?.(base);
                }
              : undefined
          }
          onPointerOver={clickable ? () => (document.body.style.cursor = 'pointer') : undefined}
          onPointerOut={clickable ? () => (document.body.style.cursor = 'auto') : undefined}
        />
      ))}
    </Instances>
  );
}

function BondInstances({ base, items }) {
  const color = (BASES[base] ?? { color: '#3b82f6' }).color;
  return (
    <Instances limit={INSTANCE_LIMIT}>
      <cylinderGeometry args={[0.06, 0.06, 1, 8]} />
      <meshStandardMaterial color={color} emissive={color} emissiveIntensity={0.35} roughness={0.35} metalness={0.1} />
      {items.map((it) => (
        <Instance key={it.key} position={it.position} quaternion={it.quaternion} scale={[1, it.length, 1]} />
      ))}
    </Instances>
  );
}

function DnaHelix({
  mode = 'display',
  pairingKind = 'dna',
  builtCount = 0,
  spin = 0.12,
  showEnzyme = false,
  radius = 1.25,
  height = 6,
  turns = 1.75,
  onBaseClick,
}) {
  const group = useRef();
  const count = TEMPLATE_STRAND.length;
  const { strandA, strandB, rungs } = useMemo(
    () => makeHelix({ count, radius, height, turns }),
    [count, radius, height, turns]
  );

  const backboneA = useMemo(() => new THREE.CatmullRomCurve3(strandA), [strandA]);
  const backboneB = useMemo(() => new THREE.CatmullRomCurve3(strandB), [strandB]);

  // Per-rung bond transforms never change with progress — compute once.
  const bondXforms = useMemo(
    () => rungs.map((rung, i) => ({ key: i, ...bondTransform(rung.a, rung.b) })),
    [rungs]
  );

  const partnerMap = pairingKind === 'transcription' ? PAIRING.transcription : PAIRING.dna;
  const activeIndex = mode === 'pairing' ? builtCount : -1;

  // Group beads / bonds by base colour for instanced drawing. The active rung's
  // template bead is excluded — it renders as a normal mesh so it can pulse.
  const { beadGroups, bondGroups } = useMemo(() => {
    const beads = {};
    const bonds = {};
    rungs.forEach((rung, i) => {
      const templateBase = TEMPLATE_STRAND[i];
      const revealed = mode !== 'pairing' || i < builtCount;
      if (i !== activeIndex) {
        (beads[templateBase] ??= []).push({ key: `t${i}`, position: rung.a.toArray() });
      }
      if (revealed) {
        const partnerBase = partnerMap[templateBase];
        (beads[partnerBase] ??= []).push({ key: `p${i}`, position: rung.b.toArray() });
        (bonds[templateBase] ??= []).push(bondXforms[i]);
      }
    });
    return { beadGroups: beads, bondGroups: bonds };
  }, [rungs, bondXforms, mode, builtCount, activeIndex, partnerMap]);

  useFrame((state, delta) => {
    if (!group.current) return;
    group.current.rotation.y += delta * spin;
    // Display centrepieces hover gently; working holograms stay put so the
    // active rung doesn't drift under the student's eye.
    if (mode === 'display') group.current.position.y = Math.sin(state.clock.elapsedTime * 0.6) * 0.07;
  });

  return (
    <group ref={group}>
      {/* Template backbone — always visible. */}
      <mesh>
        <tubeGeometry args={[backboneA, 64, 0.09, 8, false]} />
        <meshStandardMaterial
          color={theme.helix.backbone}
          emissive={theme.helix.backboneEmissive}
          emissiveIntensity={0.6}
          roughness={0.3}
          metalness={0.2}
        />
      </mesh>

      {/* Partner backbone — dims until the strand is built during pairing. */}
      <mesh>
        <tubeGeometry args={[backboneB, 64, 0.09, 8, false]} />
        <meshStandardMaterial
          color={theme.helix.backbone}
          emissive={theme.helix.backboneEmissive}
          emissiveIntensity={0.6}
          roughness={0.3}
          metalness={0.2}
          transparent
          opacity={mode === 'pairing' ? 0.18 : 1}
        />
      </mesh>

      {Object.entries(bondGroups).map(([base, items]) => (
        <BondInstances key={`b-${base}`} base={base} items={items} />
      ))}
      {Object.entries(beadGroups).map(([base, items]) => (
        <BeadInstances
          key={`n-${base}`}
          base={base}
          items={items}
          clickable={mode === 'explore'}
          onBaseClick={onBaseClick}
        />
      ))}

      {/* The rung being solved pulses, so it stays a regular animated mesh. */}
      {activeIndex >= 0 && activeIndex < rungs.length && (
        <Nucleotide base={TEMPLATE_STRAND[activeIndex]} position={rungs[activeIndex].a.toArray()} pulse />
      )}

      {/* RNA polymerase clamps whichever rung is being transcribed next. */}
      {showEnzyme && rungs[Math.min(builtCount, rungs.length - 1)] && (
        <RnaPolymerase position={rungs[Math.min(builtCount, rungs.length - 1)].mid.toArray()} />
      )}
    </group>
  );
}


// ==========================================================================
// Capsule
// ==========================================================================

// A large glass containment capsule holding a floating biology specimen.
// Reused for every sample in the lab. `children` is the specimen to display.
function Capsule({ position, radius = 1.6, height = 5, color = '#5eead4', label, sub, active = false, locked = false, children }) {
  const glow = useRef();
  const holder = useRef();
  const cy = height / 2;

  useFrame((state) => {
    const t = state.clock.elapsedTime;
    if (glow.current) {
      const base = active ? 0.5 : 0.22;
      glow.current.material.opacity = base + Math.sin(t * 1.6) * 0.06;
    }
    // Specimen floats gently; phase offset by position so capsules desync.
    if (holder.current) holder.current.position.y = cy + Math.sin(t * 0.9 + position[0]) * 0.08;
  });

  return (
    <group position={position}>
      <BlobShadow radius={radius + 0.9} />
      {/* base plinth */}
      <mesh position={[0, 0.18, 0]}>
        <cylinderGeometry args={[radius + 0.35, radius + 0.55, 0.36, 24]} />
        <meshStandardMaterial color="#0c1422" metalness={0.7} roughness={0.35} emissive={color} emissiveIntensity={active ? 0.3 : 0.08} />
      </mesh>
      {/* metal rings top & bottom */}
      <mesh position={[0, 0.42, 0]} rotation={[Math.PI / 2, 0, 0]}>
        <torusGeometry args={[radius, 0.06, 10, 32]} />
        <meshStandardMaterial color={color} emissive={color} emissiveIntensity={active ? 1 : 0.4} />
      </mesh>
      <mesh position={[0, height - 0.1, 0]}>
        <cylinderGeometry args={[radius + 0.2, radius + 0.2, 0.4, 24]} />
        <meshStandardMaterial color="#0c1422" metalness={0.7} roughness={0.35} emissive={color} emissiveIntensity={active ? 0.4 : 0.1} />
      </mesh>

      {/* inner volumetric glow (front faces only — halves the overdraw) */}
      <mesh ref={glow} position={[0, cy, 0]}>
        <cylinderGeometry args={[radius - 0.15, radius - 0.15, height - 0.6, 20, 1, true]} />
        <meshBasicMaterial color={color} transparent opacity={0.4} depthWrite={false} blending={THREE.AdditiveBlending} />
      </mesh>

      {/* the specimen */}
      <group ref={holder} position={[0, cy, 0]}>{children}</group>

      {/* glass shell (drawn last, transparent) */}
      <mesh position={[0, cy, 0]}>
        <cylinderGeometry args={[radius, radius, height - 0.5, 28, 1, true]} />
        <meshStandardMaterial color="#bfe9ff" transparent opacity={0.08} roughness={0.05} metalness={0} side={THREE.DoubleSide} depthWrite={false} />
      </mesh>

      {/* light inside to lift the specimen */}
      <pointLight position={[0, cy, 0]} intensity={active ? 14 : 6} color={color} distance={height * 1.4} />

      {/* holographic label */}
      <Html position={[0, height + 0.7, 0]} center distanceFactor={16} occlude>
        <div className={`sq-capsule-label ${locked ? 'locked' : ''} ${active ? 'active' : ''}`}>
          <span style={{ color }}>{label}</span>
          <small>{locked ? '🔒 ' + sub : sub}</small>
        </div>
      </Html>
    </group>
  );
}


// ==========================================================================
// ModelSpecimen
// ==========================================================================

// Loads any GLB and displays it as a floating specimen: recentered to its true
// world-space center, scaled to a target height, gently rotating in place.
// Used for the real DNA helix and any other capsule model that gets dropped in.
function ModelSpecimen({ url, targetHeight = 3.6, emissive = '#5eead4', spin = 0.25 }) {
  const ref = useRef();
  const { scene } = useGLTF(url);

  const { object, scale, center } = useMemo(() => {
    const obj = scene.clone(true);
    // Sketchfab models nest transforms on a root node; world matrices must be
    // resolved before measuring or the box (and thus the center) is wrong,
    // which makes the model orbit the capsule axis instead of spinning in place.
    obj.updateMatrixWorld(true);
    const box = new THREE.Box3().setFromObject(obj);
    const size = new THREE.Vector3();
    const c = new THREE.Vector3();
    box.getSize(size);
    box.getCenter(c);
    const s = targetHeight / (size.y || 1);
    obj.traverse((child) => {
      if (child.isMesh && child.material) {
        const mat = child.material.clone();
        mat.emissive = new THREE.Color(emissive);
        mat.emissiveIntensity = 0.22;
        child.material = mat;
      }
    });
    return { object: obj, scale: s, center: c };
  }, [scene, targetHeight, emissive]);

  useFrame((_, delta) => {
    if (ref.current) ref.current.rotation.y += delta * spin;
  });

  return (
    <group ref={ref}>
      {/* Scale, then translate the model so its true centre sits at the origin. */}
      <group scale={scale}>
        <primitive object={object} position={[-center.x, -center.y, -center.z]} />
      </group>
    </group>
  );
}


